example.code:
# BAD — loads orders for every user even when not requested
@strawberry.type
class User:
    @strawberry.field
    def orders(self) -> List[Order]:
        return self._orders  # pre-loaded in parent query

# GOOD — lazy load only when requested, batched via DataLoader
@strawberry.type
class User:
    @strawberry.field
    async def orders(self, info: Info, first: int = 10) -> List[Order]:
        loader = info.context.loaders.orders_by_user
        return await loader.load((self.id, first))
